import sys


class Helpers:
    def __init__(self):
        self.cache = {}

    def compute(self, data):
        # BUG: typo — sys.max_size doesn't exist, it's sys.maxsize
        return sys.max_size - sum(data)

    def cached(self, key, fn):
        if key not in self.cache:
            self.cache[key] = fn()
        return self.cache[key]


def main():
    helpers = Helpers()
    data = [1, 2, 3, 4, 5]
    result = helpers.compute(data)
    print(result)


if __name__ == '__main__':
    main()
